// AWS Solutions Architect Associate (SAA-C03) - 100 Questions
const SAA_QUESTIONS = [
{id:'saa1',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs a database solution that automatically scales read capacity across multiple Availability Zones. Which service should they use?',options:['Amazon RDS Multi-AZ','Amazon Aurora with Read Replicas','Amazon DynamoDB with DAX','Amazon ElastiCache for Redis'],correct:1,explanation:'Amazon Aurora automatically handles replica promotion in case of failure and can add up to 15 read replicas across AZs, providing both scalability and resilience.'},
{id:'saa2',exams:['saa'],domain:'Design High-Performing Architectures',text:'A web application needs to serve static assets globally with the lowest possible latency. What is the best solution?',options:['Deploy EC2 instances in every region','Use Amazon CloudFront with S3 as the origin','Use Amazon Route 53 only','Use Elastic Load Balancing'],correct:1,explanation:'CloudFront is a CDN that caches content at edge locations globally, minimizing latency for static asset delivery.'},
{id:'saa3',exams:['saa'],domain:'Design Secure Architectures',text:'A company wants to restrict access to their S3 bucket to only their CloudFront distribution. What should they use?',options:['Bucket Policy with IP restriction','Origin Access Control (OAC)','S3 CORS policy','AWS Shield'],correct:1,explanation:'Origin Access Control (OAC) is the recommended way to restrict S3 bucket access to only your CloudFront distribution, replacing the older OAI.'},
{id:'saa4',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company has EC2 instances running predictable workloads for 3 years. What is the most cost-effective pricing option?',options:['On-Demand Instances','Spot Instances','Standard Reserved Instances','Convertible Reserved Instances'],correct:2,explanation:'Standard Reserved Instances offer the highest discount (up to 72%) for steady, predictable workloads with a 1 or 3-year commitment.'},
{id:'saa5',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the difference between an RDS Multi-AZ deployment and a Read Replica?',options:['They are identical','Multi-AZ is for high availability/failover; Read Replicas are for scaling read performance','Multi-AZ is cheaper; Read Replicas are more expensive','Read Replicas are in the same AZ; Multi-AZ spans regions'],correct:1,explanation:'Multi-AZ maintains a synchronous standby for failover (HA), while Read Replicas are asynchronously replicated for read scaling.'},
{id:'saa6',exams:['saa'],domain:'Design High-Performing Architectures',text:'An application needs to process messages from a queue and requires exactly-once processing. Which SQS feature should be used?',options:['Standard Queue with long polling','FIFO Queue with message deduplication','Dead Letter Queue','Visibility timeout only'],correct:1,explanation:'SQS FIFO queues guarantee exactly-once processing and message ordering, eliminating duplicates through content-based deduplication.'},
{id:'saa7',exams:['saa'],domain:'Design Secure Architectures',text:'A company needs to allow an EC2 instance to access an S3 bucket without storing credentials. What is the best approach?',options:['Store credentials in the EC2 user data','Use an IAM Role attached to the EC2 instance','Store credentials in environment variables','Use an S3 bucket policy with the instance IP'],correct:1,explanation:'IAM Roles for EC2 instances provide temporary, automatically rotating credentials through the instance metadata service—no credentials stored.'},
{id:'saa8',exams:['saa'],domain:'Design Resilient Architectures',text:'What is an Auto Scaling lifecycle hook?',options:['A script that runs during instance termination only','Pauses instance launch or termination to perform custom actions before the instance enters service or is terminated','An alarm that triggers scaling','A hook for monitoring scaling events'],correct:1,explanation:'Lifecycle hooks pause the instance during launch or termination, allowing custom scripts to run (e.g., install software, drain connections).'},
{id:'saa9',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company needs to archive data that is rarely accessed but must be retrieved within 12 hours. Which S3 storage class is most cost-effective?',options:['S3 Standard','S3 Standard-IA','S3 Glacier Flexible Retrieval','S3 Glacier Deep Archive'],correct:3,explanation:'S3 Glacier Deep Archive is the lowest-cost storage class, designed for data retained for 7-10 years with a 12-hour retrieval time.'},
{id:'saa10',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company has a microservices application where services need to communicate asynchronously. Which combination is best?',options:['EC2 instances with direct API calls','SNS + SQS fan-out pattern','Direct Lambda-to-Lambda synchronous calls','API Gateway with RDS'],correct:1,explanation:'SNS+SQS fan-out allows one message to be delivered to multiple SQS queues, enabling async processing by multiple consumers independently.'},
{id:'saa11',exams:['saa'],domain:'Design Resilient Architectures',text:'What is a NAT Gateway used for?',options:['Connecting two VPCs','Allowing instances in a private subnet to access the internet while remaining private','Translating domain names to IPs','Balancing network traffic'],correct:1,explanation:'A NAT Gateway allows EC2 instances in private subnets to initiate outbound internet connections (e.g., updates) without being reachable from the internet.'},
{id:'saa12',exams:['saa'],domain:'Design Secure Architectures',text:'A company needs to encrypt EBS volumes. Which key management option gives them the most control?',options:['Default AWS managed keys','Customer managed keys (CMK) in KMS','AWS owned keys','No encryption needed'],correct:1,explanation:'Customer managed keys (CMKs) give you control over key rotation policies, access, and deletion, providing maximum control over encryption.'},
{id:'saa13',exams:['saa'],domain:'Design High-Performing Architectures',text:'Which database service provides microsecond read latency for DynamoDB?',options:['ElastiCache for Memcached','DynamoDB Global Tables','DynamoDB Accelerator (DAX)','DynamoDB Streams'],correct:2,explanation:'DAX (DynamoDB Accelerator) is an in-memory cache for DynamoDB that delivers up to 10x performance improvement with microsecond latency.'},
{id:'saa14',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs a multi-region active-active database for a globally distributed application. Which service should they use?',options:['RDS Multi-AZ','DynamoDB Global Tables','Aurora Global Database','ElastiCache Global Datastore'],correct:1,explanation:'DynamoDB Global Tables provides fully managed, multi-region, multi-active replication for globally distributed applications.'},
{id:'saa15',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'An application has unpredictable spikes in traffic. Which compute strategy minimizes costs while handling spikes?',options:['Large Reserved Instances for all capacity','On-Demand with Auto Scaling','Spot Instances for all workloads','Dedicated Hosts'],correct:1,explanation:'On-Demand instances with Auto Scaling handle spikes automatically and you only pay for what you use—cost-effective for unpredictable workloads.'},
{id:'saa16',exams:['saa'],domain:'Design Secure Architectures',text:'What is VPC Peering?',options:['Connecting a VPC to the internet','A networking connection between two VPCs that allows private communication between them','Connecting a VPC to on-premises network','Sharing a subnet between accounts'],correct:1,explanation:'VPC Peering is a networking connection between two VPCs enabling instances to communicate privately, as if on the same network.'},
{id:'saa17',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company wants to improve database performance with a connection pooling solution in front of RDS. Which service should they use?',options:['ElastiCache','RDS Proxy','Aurora Multi-Master','DynamoDB DAX'],correct:1,explanation:'RDS Proxy manages a pool of database connections, improving application scalability and resilience by efficiently sharing connections.'},
{id:'saa18',exams:['saa'],domain:'Design Resilient Architectures',text:'Which Route 53 routing policy distributes traffic based on the health of endpoints?',options:['Simple routing','Weighted routing','Failover routing','Geolocation routing'],correct:2,explanation:'Failover routing directs traffic to a primary endpoint and automatically fails over to a secondary if the primary is unhealthy.'},
{id:'saa19',exams:['saa'],domain:'Design Secure Architectures',text:'A company wants to implement defense-in-depth for their VPC. Which combination provides multiple security layers?',options:['Security Groups alone','NACLs alone','Security Groups + NACLs + VPC Flow Logs','WAF alone'],correct:2,explanation:'Defense-in-depth uses multiple controls: Security Groups (instance-level stateful), NACLs (subnet-level stateless), and Flow Logs for visibility.'},
{id:'saa20',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'What is the benefit of using S3 Intelligent-Tiering?',options:['Lowest storage cost for all data','Automatically moves data between access tiers based on usage patterns to optimize costs','Fastest retrieval for all objects','Unlimited storage with no cost'],correct:1,explanation:'S3 Intelligent-Tiering automatically moves data between frequent and infrequent access tiers based on access patterns, optimizing costs without performance impact.'},
{id:'saa21',exams:['saa'],domain:'Design High-Performing Architectures',text:'An application needs to process millions of events per second from IoT devices. Which service is most appropriate?',options:['Amazon SQS','Amazon Kinesis Data Streams','Amazon SNS','Amazon MQ'],correct:1,explanation:'Amazon Kinesis Data Streams is built for high-throughput real-time streaming, capable of processing millions of records per second with sub-second latency.'},
{id:'saa22',exams:['saa'],domain:'Design Resilient Architectures',text:'What is an Application Load Balancer (ALB) target group?',options:['A security group for the load balancer','A group of resources that receive traffic from the load balancer, routed based on rules','A group of load balancers for redundancy','An auto scaling group'],correct:1,explanation:'Target groups route requests to registered targets (EC2, containers, Lambda) based on routing rules configured on the ALB listeners.'},
{id:'saa23',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS PrivateLink?',options:['A VPN service','Provides private connectivity between VPCs, AWS services, and on-premises without exposing traffic to the internet','A private internet connection','A private DNS service'],correct:1,explanation:'AWS PrivateLink provides private network access to AWS services and third-party services using VPC endpoints, keeping traffic off the internet.'},
{id:'saa24',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company needs to migrate a relational database to AWS with minimal downtime. Which service should they use?',options:['AWS Server Migration Service','AWS Database Migration Service (DMS)','AWS DataSync','AWS Snowball'],correct:1,explanation:'AWS DMS migrates databases to AWS with minimal downtime, supporting homogeneous and heterogeneous migrations, and continuous replication.'},
{id:'saa25',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'Which S3 feature can automatically delete old object versions to reduce storage costs?',options:['S3 Versioning','S3 Lifecycle Policies','S3 Transfer Acceleration','S3 Replication'],correct:1,explanation:'S3 Lifecycle Policies automate the transition of objects between storage classes and expiration (deletion) based on age or rules.'},
{id:'saa26',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the purpose of an Elastic IP address?',options:['An IP that automatically scales','A static public IPv4 address that can be remapped to different instances for failover scenarios','A private IP for VPC-internal communication','An IP address that reduces latency'],correct:1,explanation:'Elastic IP is a static public IP that you can remap from a failed instance to a healthy one, enabling rapid failover for public-facing resources.'},
{id:'saa27',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon EFS and when would you use it over EBS?',options:['EFS is block storage; use it for databases','EFS is a shared NFS file system that can be mounted by multiple EC2 instances simultaneously; use it for shared file access','EFS is cheaper than EBS in all cases','EFS has better throughput than EBS for all workloads'],correct:1,explanation:'EFS provides shared file storage accessible by multiple EC2 instances across AZs simultaneously, unlike EBS which attaches to one instance.'},
{id:'saa28',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Organizations Service Control Policy (SCP)?',options:['A policy for managing AWS support cases','A policy that sets maximum available permissions for accounts in an organization, acting as guardrails','A billing control policy','A network access control policy'],correct:1,explanation:'SCPs set the maximum permissions available to accounts in an AWS Organization, overriding even Administrator permissions—they are guardrails, not grants.'},
{id:'saa29',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs to run a stateless web application that must handle sudden traffic spikes. What is the best architecture?',options:['Single large EC2 instance','Auto Scaling Group with ALB across multiple AZs','Reserved Instances with manual scaling','Single EC2 with large EBS volume'],correct:1,explanation:'An ASG with ALB across multiple AZs provides horizontal scaling and fault tolerance—perfect for stateless web apps with variable traffic.'},
{id:'saa30',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon CloudFront Functions?',options:['A serverless compute service','Lightweight JavaScript functions that run at CloudFront edge locations for HTTP request/response manipulation','A function for managing CloudFront distributions','A cost function for CloudFront pricing'],correct:1,explanation:'CloudFront Functions are lightweight JavaScript functions that execute at edge locations with sub-millisecond latency for HTTP manipulation like URL rewrites.'},
{id:'saa31',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company runs batch processing jobs that can be interrupted. Which pricing strategy minimizes costs?',options:['On-Demand Instances','Reserved Instances','Spot Instances with Spot Fleet','Dedicated Instances'],correct:2,explanation:'Spot Instances with Spot Fleet offer the lowest cost (up to 90% off On-Demand) and Spot Fleet maintains target capacity by requesting from multiple pools.'},
{id:'saa32',exams:['saa'],domain:'Design Resilient Architectures',text:'What is cross-region replication in S3?',options:['Copying files between S3 buckets in the same region','Automatically replicating objects from one S3 bucket to a bucket in a different AWS region','Duplicating an S3 bucket within the same account','Backing up S3 to Glacier'],correct:1,explanation:'Cross-Region Replication (CRR) automatically copies objects from a source bucket to a destination bucket in a different AWS region.'},
{id:'saa33',exams:['saa'],domain:'Design Secure Architectures',text:'What is the difference between an IAM User and IAM Role?',options:['IAM Users are for humans; roles are for AWS services only','IAM Users have permanent credentials; IAM Roles provide temporary credentials that can be assumed by users, services, or applications','IAM Users are more secure than roles','IAM Roles can only be used within the same account'],correct:1,explanation:'IAM Users have long-term credentials. IAM Roles provide temporary security credentials and can be assumed by anyone or any service authorized to do so.'},
{id:'saa34',exams:['saa'],domain:'Design High-Performing Architectures',text:'Which Route 53 routing policy routes users to the endpoint with the lowest latency?',options:['Simple routing','Weighted routing','Failover routing','Latency-based routing'],correct:3,explanation:'Latency-based routing directs traffic to the AWS region that provides the lowest latency for the user making the DNS request.'},
{id:'saa35',exams:['saa'],domain:'Design Resilient Architectures',text:'A company wants to design an application for disaster recovery with an RTO of 1 hour and RPO of 15 minutes. Which DR strategy is appropriate?',options:['Backup and Restore','Pilot Light','Warm Standby','Multi-Site Active/Active'],correct:2,explanation:'Warm Standby keeps a scaled-down fully functional copy running, allowing quick scale-up. RTO of 1hr and RPO of 15min match this strategy.'},
{id:'saa36',exams:['saa'],domain:'Design Secure Architectures',text:'What is Amazon Macie and when should you use it?',options:['For managing EC2 instance configurations','To automatically discover and protect sensitive data (PII, credentials) stored in S3 using ML','For monitoring database query performance','For detecting network intrusions'],correct:1,explanation:'Amazon Macie uses ML to automatically discover, classify, and protect sensitive data like PII and credentials stored in S3.'},
{id:'saa37',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Provisioned IOPS SSD (io1/io2) in EBS used for?',options:['Archiving cold data','High-performance applications requiring predictable storage performance like large databases','Temporary instance storage','Shared storage for containers'],correct:1,explanation:'Provisioned IOPS SSD volumes are designed for I/O-intensive workloads like relational databases that need consistent, predictable performance.'},
{id:'saa38',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company has nightly batch jobs that take 6 hours. The jobs can restart from checkpoints if interrupted. What is the most cost-effective compute option?',options:['On-Demand EC2','Reserved EC2','Spot Instances','Dedicated Hosts'],correct:2,explanation:'Spot Instances are ideal for batch jobs with checkpointing—they can be interrupted but restart from checkpoints, offering up to 90% cost savings.'},
{id:'saa39',exams:['saa'],domain:'Design Resilient Architectures',text:'What is Amazon EventBridge used for in event-driven architectures?',options:['Physical event management','Routing events from AWS services, custom apps, and SaaS to various targets based on rules','Database change data capture only','Sending push notifications to mobile devices'],correct:1,explanation:'EventBridge is a serverless event bus that routes events from sources (AWS services, apps, SaaS) to targets based on flexible matching rules.'},
{id:'saa40',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Systems Manager Parameter Store used for?',options:['Managing physical server parameters','Storing configuration data and secrets (strings, passwords, connection strings) securely for applications','Managing EC2 instance parameters only','A KMS alternative for encryption'],correct:1,explanation:'Parameter Store provides secure storage for configuration data and secrets, with optional encryption using KMS, accessible by applications and Lambda.'},
{id:'saa41',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company needs to decouple a monolithic application. Their service sends thousands of messages per second to downstream processors. Which solution is best?',options:['Direct HTTP calls between services','Amazon SQS with multiple consumer groups','A single Lambda function','Amazon SNS alone'],correct:1,explanation:'SQS decouples producers from consumers, buffers messages, and allows multiple consumer groups to scale independently, handling thousands of messages/sec.'},
{id:'saa42',exams:['saa'],domain:'Design Resilient Architectures',text:'What does "blue/green deployment" mean?',options:['A color-coding system for server priority','Running two identical environments where traffic shifts from blue (current) to green (new) for zero-downtime deployments','A network traffic visualization technique','A cost optimization strategy for idle instances'],correct:1,explanation:'Blue/green deployment maintains two identical environments. Traffic shifts from blue (current) to green (new) enabling instant rollback if issues occur.'},
{id:'saa43',exams:['saa'],domain:'Design Secure Architectures',text:'What is S3 Object Lock used for?',options:['Locking buckets from new object uploads','Storing objects using WORM (Write Once Read Many) model to prevent deletion or modification for a retention period','Locking S3 access to one account','Encrypting objects at rest'],correct:1,explanation:'S3 Object Lock enforces WORM protection—objects cannot be deleted or overwritten during a retention period, supporting compliance requirements.'},
{id:'saa44',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is AWS Global Accelerator and how does it differ from CloudFront?',options:['They are identical services','Global Accelerator routes TCP/UDP traffic using the AWS global network for IP applications; CloudFront is an HTTP CDN for content caching','Global Accelerator is only for games','CloudFront has lower latency than Global Accelerator for all cases'],correct:1,explanation:'Global Accelerator optimizes routing of TCP/UDP traffic using static IPs and the AWS backbone, while CloudFront caches HTTP/HTTPS content at edges.'},
{id:'saa45',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company has databases that are only used during business hours (8am-6pm). How can they reduce costs?',options:['Move to spot instances','Schedule RDS to stop during non-business hours using Lambda and EventBridge','Use Reserved Instances','Switch to Glacier storage'],correct:1,explanation:'Scheduling RDS stop/start using EventBridge + Lambda can save ~50% by stopping databases outside business hours.'},
{id:'saa46',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the purpose of AWS Backup?',options:['Backing up your IAM credentials','A centralized, fully managed backup service for automating backup across AWS services','Backup software for on-premises servers','S3 data archiving only'],correct:1,explanation:'AWS Backup provides a centralized service to automate and manage backups across RDS, DynamoDB, EFS, EBS, EC2, and more.'},
{id:'saa47',exams:['saa'],domain:'Design High-Performing Architectures',text:'Which ELB type is best suited for microservices and container-based architectures with path-based and host-based routing?',options:['Classic Load Balancer','Network Load Balancer','Application Load Balancer','Gateway Load Balancer'],correct:2,explanation:'ALB (Layer 7) supports advanced request routing based on URL path, host headers, HTTP methods, and query strings—ideal for microservices.'},
{id:'saa48',exams:['saa'],domain:'Design Secure Architectures',text:'A company stores sensitive customer data in DynamoDB. What should they enable to meet compliance requirements?',options:['DynamoDB Streams','DynamoDB encryption at rest using KMS and enable CloudTrail for audit logging','DynamoDB DAX only','DynamoDB TTL'],correct:1,explanation:'Enabling KMS encryption at rest and CloudTrail logging ensures data is encrypted and all API actions are audited for compliance.'},
{id:'saa49',exams:['saa'],domain:'Design Resilient Architectures',text:'What is Amazon Aurora Serverless?',options:['Aurora without any database features','An on-demand, auto-scaling configuration for Aurora that automatically adjusts capacity based on application needs','A serverless alternative to Lambda','Aurora without Multi-AZ'],correct:1,explanation:'Aurora Serverless automatically starts, shuts down, and scales capacity up or down based on application needs, ideal for infrequent or unpredictable workloads.'},
{id:'saa50',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is DynamoDB Streams?',options:['A video streaming service built on DynamoDB','A feature that captures time-ordered sequence of item-level modifications in a DynamoDB table','DynamoDB pricing for high throughput','A DynamoDB caching layer'],correct:1,explanation:'DynamoDB Streams captures item-level changes in chronological order, enabling event-driven architectures, replication, and audit trails.'},
{id:'saa51',exams:['saa'],domain:'Design Resilient Architectures',text:'A company uses EC2 instances with stateful sessions. They need high availability. Which ALB feature handles this?',options:['Path-based routing','Sticky sessions (session affinity)','Host-based routing','Lambda targets'],correct:1,explanation:'Sticky sessions use cookies to bind a user session to a specific target, ensuring stateful sessions always reach the same instance.'},
{id:'saa52',exams:['saa'],domain:'Design Secure Architectures',text:'What is the purpose of AWS Resource Access Manager (RAM)?',options:['Managing RAM memory for EC2 instances','Securely sharing AWS resources across AWS accounts or within an AWS Organization','A random access memory monitoring service','A resource usage reporting tool'],correct:1,explanation:'AWS RAM lets you share resources (like VPC subnets, Transit Gateways, Route 53 zones) with other accounts without creating duplicates.'},
{id:'saa53',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'What is the most cost-effective way to run a Lambda function that needs to process S3 uploads and does not need predictable execution time?',options:['Provisioned Concurrency','On-Demand Lambda with S3 event trigger','Reserved Concurrency only','EC2 with S3 polling'],correct:1,explanation:'On-Demand Lambda triggered by S3 events costs nothing when idle and scales automatically—most cost-effective for unpredictable S3 processing.'},
{id:'saa54',exams:['saa'],domain:'Design Resilient Architectures',text:'What is AWS Elastic Disaster Recovery (DRS)?',options:['A manual backup and restore process','Minimizes downtime and data loss by continuously replicating on-premises or cloud-based applications to AWS for fast recovery','A cold DR solution using S3 Glacier','An EC2 snapshot service'],correct:1,explanation:'AWS DRS (formerly CloudEndure) continuously replicates machines to AWS and enables fast recovery to minimize RTO/RPO.'},
{id:'saa55',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon S3 Transfer Acceleration?',options:['A tool to speed up S3 bucket creation','Accelerates long-distance S3 uploads using CloudFront edge locations and the AWS backbone network','Faster S3 downloads for Prime customers','Accelerated S3 replication between regions'],correct:1,explanation:'S3 Transfer Acceleration speeds up uploads from clients far from the S3 bucket by routing through the nearest CloudFront edge location.'},
{id:'saa56',exams:['saa'],domain:'Design Secure Architectures',text:'What are Gateway VPC Endpoints used for?',options:['Connecting VPCs to on-premises','Providing private access to S3 and DynamoDB without needing a NAT Gateway or internet access','Creating a gateway for internet access','Load balancing at the gateway level'],correct:1,explanation:'Gateway endpoints are VPC endpoints for S3 and DynamoDB that allow private access without routing traffic through NAT Gateway or internet.'},
{id:'saa57',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs their application to detect and automatically recover from instance failures. What should they use?',options:['Manual monitoring and replacement','EC2 Auto Recovery using CloudWatch Alarms','Reserved Instance auto-recovery','EBS snapshot recovery'],correct:1,explanation:'EC2 Auto Recovery uses CloudWatch alarms to detect system-level failures and automatically recover the instance on the same hardware with the same attributes.'},
{id:'saa58',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon OpenSearch Service used for?',options:['Patent/IP search management','Deploying, operating, and scaling Elasticsearch-compatible clusters for log analytics, search, and visualization','Finding open source software','Network port scanning'],correct:1,explanation:'Amazon OpenSearch Service (formerly Elasticsearch Service) provides managed clusters for log analytics, full-text search, and real-time application monitoring.'},
{id:'saa59',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company wants to reduce NAT Gateway costs for EC2 instances that only access S3 and DynamoDB. What should they do?',options:['Switch to Spot instances','Replace NAT Gateway with Gateway VPC Endpoints for S3 and DynamoDB','Use smaller NAT Gateway','Eliminate all private subnets'],correct:1,explanation:'Gateway VPC Endpoints for S3/DynamoDB provide free private access, eliminating NAT Gateway data processing costs for these destinations.'},
{id:'saa60',exams:['saa'],domain:'Design Resilient Architectures',text:'What is an SQS Dead Letter Queue (DLQ)?',options:['A queue for deleting messages','A queue where messages are sent after failing to be processed a maximum number of times','A queue for urgent/priority messages','A backup queue in another region'],correct:1,explanation:'A DLQ receives messages that fail processing after the configured maxReceiveCount, allowing investigation of failed messages without losing them.'},
{id:'saa61',exams:['saa'],domain:'Design High-Performing Architectures',text:'A gaming application needs single-digit millisecond read/write performance for leaderboards. Which is the best database choice?',options:['RDS MySQL','Amazon Redshift','DynamoDB with DAX','Aurora PostgreSQL'],correct:2,explanation:'DynamoDB provides single-digit millisecond performance, and DAX adds microsecond caching—perfect for high-performance gaming leaderboards.'},
{id:'saa62',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Firewall Manager?',options:['A physical firewall appliance','Centrally configures and manages firewall rules (WAF, Shield, Security Groups, Network Firewall) across accounts and applications','A VPC firewall for individual instances','An on-premises firewall management tool'],correct:1,explanation:'AWS Firewall Manager provides centralized management of WAF rules, Shield protections, Security Groups, and Network Firewall policies across an Organization.'},
{id:'saa63',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company has Lambda functions that process data from DynamoDB Streams. They are concerned about costs with high DynamoDB write activity. What should they consider?',options:['Increase Lambda memory to process faster','Enable DynamoDB Streams filtering to only invoke Lambda for relevant events','Switch from DynamoDB to RDS','Use reserved concurrency for Lambda'],correct:1,explanation:'EventBridge Pipes or Lambda event filtering reduces the number of Lambda invocations by filtering events at the source, reducing costs.'},
{id:'saa64',exams:['saa'],domain:'Design Resilient Architectures',text:'What is Amazon Route 53 health checking?',options:['Monitoring the health of your Route 53 account','Monitoring the health and availability of endpoints, allowing Route 53 to route traffic away from unhealthy resources','Checking DNS propagation health','Monitoring DNS query success rates'],correct:1,explanation:'Route 53 health checks monitor endpoint availability and integrate with routing policies to automatically route traffic away from unhealthy endpoints.'},
{id:'saa65',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company needs a message broker that supports multiple protocols (AMQP, MQTT, STOMP) for migrating existing applications. Which service is best?',options:['Amazon SQS','Amazon SNS','Amazon MQ','Amazon Kinesis'],correct:2,explanation:'Amazon MQ is a managed message broker service for ActiveMQ and RabbitMQ, supporting standard messaging protocols for migrating existing applications.'},
{id:'saa66',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Network Firewall?',options:['A physical firewall device','A stateful managed network firewall and IDS/IPS service for VPCs with fine-grained traffic inspection','A next-generation anti-virus service','A firewall for Lambda functions'],correct:1,explanation:'AWS Network Firewall provides stateful inspection, IDS/IPS, and web filtering for VPCs, giving fine-grained control over network traffic.'},
{id:'saa67',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the purpose of Amazon SQS visibility timeout?',options:['Hiding sensitive message content','The period during which SQS prevents other consumers from receiving a message being processed','The time before a message expires','The delay before a message becomes visible'],correct:1,explanation:'Visibility timeout hides a message from other consumers while it is being processed, preventing double-processing if processing takes time.'},
{id:'saa68',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is AWS Lambda Provisioned Concurrency?',options:['Limits on concurrent Lambda executions','Pre-initializing a specified number of Lambda instances to eliminate cold starts for latency-sensitive applications','Reserved capacity for Lambda in one region','Lambda clusters for high performance'],correct:1,explanation:'Provisioned Concurrency keeps Lambda functions pre-initialized and ready to respond immediately, eliminating cold start latency for critical functions.'},
{id:'saa69',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company runs EC2 instances in 3 regions. How can they identify the cheapest region for their workload?',options:['Manually compare prices on the console','Use AWS Pricing Calculator and compare on-demand prices per region, considering data transfer costs','Always use us-east-1 as it is cheapest','Use AWS Cost Explorer to compare regional costs'],correct:3,explanation:'AWS Cost Explorer can analyze historical costs by region, and the Pricing Calculator can estimate future costs, helping identify the most cost-effective region.'},
{id:'saa70',exams:['saa'],domain:'Design Resilient Architectures',text:'What is Amazon RDS automated backup?',options:['A manual backup process you trigger','Automatically backs up your entire DB instance during a daily backup window with point-in-time recovery capability','Backup performed by AWS Support','Exporting DB to S3 manually'],correct:1,explanation:'RDS automated backups create daily snapshots and transaction logs, enabling point-in-time recovery to any second within the retention period (up to 35 days).'},
{id:'saa71',exams:['saa'],domain:'Design Secure Architectures',text:'What is the purpose of IAM Permission Boundaries?',options:['Physical limits on IAM accounts','Sets the maximum permissions that an IAM entity (user or role) can have, even if their policies grant more','The geographic boundary for IAM access','A limit on the number of IAM policies'],correct:1,explanation:'Permission Boundaries define the maximum permissions an IAM principal can have, acting as a guardrail—useful for delegating administration safely.'},
{id:'saa72',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company needs to process files uploaded to S3 immediately. Which architecture minimizes latency?',options:['Poll S3 with Lambda every minute','Use S3 Event Notifications to trigger Lambda directly','Use SQS between S3 and Lambda','Use CloudWatch Events to poll S3'],correct:1,explanation:'S3 Event Notifications can trigger Lambda directly and near-instantly when objects are created, minimizing processing latency.'},
{id:'saa73',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the difference between horizontal and vertical scaling in AWS?',options:['They are the same','Horizontal scaling adds more instances; vertical scaling increases the size/power of an existing instance','Horizontal is more expensive always','Vertical scaling is preferred by AWS'],correct:1,explanation:'Horizontal scaling (scale out) adds instances for better resilience and cost efficiency. Vertical scaling (scale up) increases instance size with a brief downtime.'},
{id:'saa74',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'What is AWS Cost Categories?',options:['A way to group services into pricing tiers','A feature to group and categorize AWS costs using custom rules for better cost allocation and reporting','A billing category set by AWS','Cost thresholds for service limits'],correct:1,explanation:'AWS Cost Categories lets you define custom grouping rules to categorize your cost and usage information by team, project, environment, or any dimension.'},
{id:'saa75',exams:['saa'],domain:'Design High-Performing Architectures',text:'Which storage type is best for a shared file system accessed by multiple Windows EC2 instances?',options:['Amazon EBS','Amazon S3','Amazon FSx for Windows File Server','Amazon EFS'],correct:2,explanation:'Amazon FSx for Windows File Server is a fully managed native Windows file system supporting SMB protocol, Active Directory, and NTFS—ideal for Windows workloads.'},
{id:'saa76',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs to ensure data written to S3 is replicated to another region for compliance. What should they enable?',options:['S3 Versioning only','Cross-Region Replication (CRR) with S3 Versioning enabled on both source and destination buckets','S3 Lifecycle Policies','S3 Transfer Acceleration'],correct:1,explanation:'CRR requires versioning enabled on both buckets and automatically replicates new objects (and optionally existing objects) to another region.'},
{id:'saa77',exams:['saa'],domain:'Design Secure Architectures',text:'What is Cognito User Pool vs Identity Pool?',options:['They are identical','User Pools handle authentication (sign-up/sign-in); Identity Pools provide temporary AWS credentials for authenticated/unauthenticated users','User Pools are for enterprises; Identity Pools are for consumers','Identity Pools handle authentication; User Pools provide AWS credentials'],correct:1,explanation:'Cognito User Pools provide authentication (user directory). Identity Pools (Federated Identities) exchange identity tokens for temporary AWS credentials.'},
{id:'saa78',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Placement Groups in EC2?',options:['A security feature for grouping EC2 instances','Logical groupings that influence instance placement to achieve low latency (cluster), spread across hardware (spread), or partition fault domains'],correct:1,explanation:'Placement groups: Cluster (low latency, same rack), Spread (different hardware racks), Partition (groups on different partitions for big data apps).'},
{id:'saa79',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company wants to move infrequently accessed data in S3 Standard to a cheaper tier automatically. What should they configure?',options:['Manual data migration scripts','S3 Lifecycle rules to transition objects to S3-IA or Glacier after a set period','S3 Replication to a cheaper region','S3 Intelligent-Tiering for all buckets'],correct:1,explanation:'S3 Lifecycle rules automate transitioning objects between storage classes (e.g., Standard → Standard-IA after 30 days, → Glacier after 90 days).'},
{id:'saa80',exams:['saa'],domain:'Design Resilient Architectures',text:'What is an AWS Availability Zone ID?',options:['A unique identifier for each AWS account in an AZ','A unique identifier for each physical AZ that maps consistently across accounts, unlike AZ names which vary per account','The ID of a specific EC2 instance in an AZ','A billing identifier for cross-AZ traffic'],correct:1,explanation:'AZ IDs are consistent across accounts (e.g., use1-az1), while AZ names (us-east-1a) may map to different physical AZs per account—use IDs for resource sharing.'},
{id:'saa81',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon S3 Select?',options:['A tool for selecting S3 storage classes','SQL-like queries that retrieve a subset of data from S3 objects, reducing data transfer and improving performance','A feature to select the fastest S3 region','A GUI for browsing S3 objects'],correct:1,explanation:'S3 Select uses SQL expressions to retrieve only the needed data from objects (CSV, JSON, Parquet), reducing data transfer and improving processing speed.'},
{id:'saa82',exams:['saa'],domain:'Design Secure Architectures',text:'What is Amazon Inspector finding severity?',options:['An AWS support priority level','Findings are scored using the Common Vulnerability Scoring System (CVSS) to prioritize vulnerabilities by severity','A compliance pass/fail rating','A network traffic risk score'],correct:1,explanation:'Amazon Inspector uses CVSS scores to rate findings as Critical, High, Medium, Low, or Informational, helping prioritize vulnerability remediation.'},
{id:'saa83',exams:['saa'],domain:'Design Resilient Architectures',text:'What is AWS Elastic Beanstalk supported deployment policies?',options:['Only All-at-once deployments','All-at-once, Rolling, Rolling with additional batch, Immutable, Traffic splitting, and Blue/Green','Only Rolling and Blue/Green','Only Immutable deployments'],correct:1,explanation:'Elastic Beanstalk supports multiple deployment policies from fastest (all-at-once) to safest (immutable/blue-green), each with different availability tradeoffs.'},
{id:'saa84',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon Kinesis Data Firehose?',options:['A fire suppression service for data centers','A fully managed service for loading streaming data into S3, Redshift, OpenSearch, and Splunk','A real-time data processing service with custom code','A fire safety monitoring service'],correct:1,explanation:'Kinesis Data Firehose is the easiest way to reliably load streaming data into data lakes and warehouses without managing infrastructure.'},
{id:'saa85',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Verified Access?',options:['A service to verify AWS account authenticity','Provides secure, Zero Trust access to corporate applications without a VPN, verifying every request','A compliance verification service','A tool for verifying IAM policy correctness'],correct:1,explanation:'AWS Verified Access provides secure access to corporate applications without VPN, using identity and device security signals for every request.'},
{id:'saa86',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company runs thousands of short-lived EC2 tasks (< 1 minute each). What is the most cost-effective compute option?',options:['EC2 On-Demand with 60-second billing','AWS Lambda with a maximum 15-minute timeout','Reserved EC2 instances','Spot Instances'],correct:1,explanation:'Lambda bills per request and per 1ms of duration—far more cost-effective than EC2 for short-lived tasks, as EC2 has a minimum 60-second billing period.'},
{id:'saa87',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs durable, long-term storage for compliance archives that will never be accessed but must be retained for 10 years. Which S3 class is best?',options:['S3 Standard','S3-IA','S3 Glacier Flexible Retrieval','S3 Glacier Deep Archive'],correct:3,explanation:'S3 Glacier Deep Archive is the lowest-cost storage, designed for compliance archives retained for 7-10+ years, with 12-hour retrieval time.'},
{id:'saa88',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Multi-AZ in the context of Elastic Load Balancing?',options:['Having multiple load balancers','Configuring ELB to distribute traffic across EC2 instances in multiple AZs for fault tolerance and scalability','Multiple accounts accessing one ELB','ELB serving multiple regions'],correct:1,explanation:'Enabling Multi-AZ in ELB allows it to distribute traffic across instances in multiple AZs, improving fault tolerance if one AZ becomes unavailable.'},
{id:'saa89',exams:['saa'],domain:'Design Secure Architectures',text:'What is an AWS Service Control Policy (SCP) guardrail?',options:['A policy that grants permissions','A restriction applied at the Organization level that limits what actions can be taken across all accounts in an OU, regardless of IAM policies','A CloudWatch alarm policy','A network routing restriction'],correct:1,explanation:'SCPs are guardrails—they restrict (not grant) permissions for all accounts in an OU, even overriding administrator permissions in those accounts.'},
{id:'saa90',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'What is EC2 Fleet?',options:['A fleet management tool for physical servers','A feature to launch and manage a combination of On-Demand, Reserved, and Spot instances across instance types and AZs','A group of EC2 instances in one AZ only','An EC2 pricing model'],correct:1,explanation:'EC2 Fleet lets you launch a mix of instance types and purchase options (On-Demand, Reserved, Spot) to optimize scale, performance, and cost.'},
{id:'saa91',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the purpose of DynamoDB TTL (Time to Live)?',options:['Setting expiration on DynamoDB tables','Automatically deleting items from a table after a specified timestamp, reducing storage costs','Limiting query execution time','Setting session timeout for DynamoDB connections'],correct:1,explanation:'DynamoDB TTL automatically deletes expired items (based on a timestamp attribute) at no cost, ideal for session data, logs, or temporary data.'},
{id:'saa92',exams:['saa'],domain:'Design High-Performing Architectures',text:'A company needs a solution to cache database queries at the application tier. Which ElastiCache engine supports complex data structures like sorted sets for leaderboards?',options:['ElastiCache for Memcached','ElastiCache for Redis'],correct:1,explanation:'ElastiCache for Redis supports advanced data structures like sorted sets, lists, and hashes, making it ideal for leaderboards, session stores, and pub/sub.'},
{id:'saa93',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Well-Architected Framework Security pillar focus?',options:['Reducing AWS costs','Protecting information and systems through identity, detection, infrastructure protection, data protection, and incident response','Maximizing application performance','Deploying applications faster'],correct:1,explanation:'The Security pillar covers five areas: IAM, detective controls, infrastructure protection, data protection, and incident response to protect workloads.'},
{id:'saa94',exams:['saa'],domain:'Design Resilient Architectures',text:'What is the purpose of an Auto Scaling Cooldown Period?',options:['Cooling down overheated servers','A period after a scaling activity during which no further scaling actions occur, preventing rapid oscillation','The time it takes for an instance to become healthy','A period for reducing instance size'],correct:1,explanation:'The cooldown period pauses Auto Scaling activity after a scaling event, allowing metrics to stabilize before triggering another action.'},
{id:'saa95',exams:['saa'],domain:'Design Cost-Optimized Architectures',text:'A company wants to optimize Lambda costs. Their functions run frequently with consistent load. What should they evaluate?',options:['Switching to EC2','Using Compute Savings Plans for Lambda to get up to 17% savings','Using reserved Lambda','Increasing Lambda timeout'],correct:1,explanation:'Compute Savings Plans cover Lambda usage and offer up to 17% savings compared to on-demand Lambda pricing with a 1 or 3-year commitment.'},
{id:'saa96',exams:['saa'],domain:'Design Resilient Architectures',text:'What is Amazon FSx for Lustre?',options:['A German-style file system','A fully managed high-performance file system for compute-intensive workloads like HPC, ML, and video processing','A Lustre luxury storage tier','A low-cost archive file system'],correct:1,explanation:'FSx for Lustre is a high-performance file system that processes datasets at over 100 GB/s with sub-millisecond latencies, optimized for HPC and ML workloads.'},
{id:'saa97',exams:['saa'],domain:'Design High-Performing Architectures',text:'What is Amazon ElastiCache write-through strategy?',options:['Writing data directly to disk only','Writing data to cache and database simultaneously, keeping cache always up-to-date at the cost of slightly higher write latency','Writing only to cache and syncing to DB later','Writing to DB only and populating cache on reads'],correct:1,explanation:'Write-through updates the cache and database on every write, ensuring cache consistency at the cost of slightly higher write latency.'},
{id:'saa98',exams:['saa'],domain:'Design Resilient Architectures',text:'What is AWS Resilience Hub?',options:['A physical hub for resilient hardware','A service to define, validate, and track the resilience of AWS applications, ensuring they meet RTO and RPO targets','A disaster recovery service for on-premises','A monitoring service for network resilience'],correct:1,explanation:'AWS Resilience Hub helps you define and validate resilience goals (RTO/RPO) for your applications, providing recommendations to meet them.'},
{id:'saa99',exams:['saa'],domain:'Design Secure Architectures',text:'What is AWS Artifact used for in enterprise compliance?',options:['Artifact management in CI/CD','Accessing AWS compliance reports (SOC, PCI, ISO) and managing agreements like BAA for HIPAA compliance','Storing application artifacts in S3','Tracking compliance of your own applications'],correct:1,explanation:'AWS Artifact provides on-demand access to AWS compliance reports and allows enterprises to manage agreements like Business Associate Agreements (BAA) for HIPAA.'},
{id:'saa100',exams:['saa'],domain:'Design Resilient Architectures',text:'A company needs a message queue that ensures messages are processed in the exact order they were sent, with no duplicates. What should they use?',options:['SQS Standard Queue','SQS FIFO Queue','SNS FIFO Topic','Amazon MQ with ordering'],correct:1,explanation:'SQS FIFO queues guarantee exactly-once processing and strict first-in, first-out ordering, unlike Standard queues which offer best-effort ordering.'},
];
